import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getSlotById, getAvailableSeats, bookSeats, processPayment } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const PAYMENT_METHODS = ['UPI','CARD','NETBANKING','WALLET'];
const PM_ICONS = { UPI:'📱', CARD:'💳', NETBANKING:'🏦', WALLET:'👛' };

const BookingPage = () => {
  const { slotId } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [slot, setSlot] = useState(null);
  const [seatSlots, setSeatSlots] = useState([]);
  const [selectedSeats, setSelectedSeats] = useState([]);
  const [loading, setLoading] = useState(true);
  const [step, setStep] = useState(1);
  const [payMethod, setPayMethod] = useState('UPI');
  const [booking, setBooking] = useState(null);
  const [processing, setProcessing] = useState(false);

  useEffect(() => {
    const load = async () => {
      try {
        const [slRes, seatsRes] = await Promise.all([getSlotById(slotId), getAvailableSeats(slotId)]);
        setSlot(slRes.data.data);
        setSeatSlots(seatsRes.data.data || []);
      } catch { toast.error('Failed to load'); }
      finally { setLoading(false); }
    };
    load();
  }, [slotId]);

  const toggleSeat = (ss) => {
    if (selectedSeats.find(s=>s.seatSlotId===ss.seatSlotId)) {
      setSelectedSeats(prev=>prev.filter(s=>s.seatSlotId!==ss.seatSlotId));
    } else {
      if (selectedSeats.length>=10){toast.error('Max 10 seats');return;}
      setSelectedSeats(prev=>[...prev,ss]);
    }
  };

  const total = selectedSeats.reduce((s,ss)=>s+parseFloat(ss.price||0),0);

  const handleBook = async () => {
    if (selectedSeats.length===0){toast.error('Select at least one seat');return;}
    setProcessing(true);
    try {
      const res = await bookSeats({ userId:user.userId, slotId:parseInt(slotId), seatIds:selectedSeats.map(s=>s.seat.seatId), discount:0, paymentMethod:payMethod });
      const reservation = res.data.data;
      const txnRes = await processPayment({ reservationId:reservation.reservationId, paymentMethod:payMethod, amount:total, discountAmount:0, transactionRef:null });
      setBooking({ reservation, transaction:txnRes.data.data });
      setStep(3);
      toast.success('Booking confirmed! Check your email.');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Booking failed');
    } finally { setProcessing(false); }
  };

  if (loading) return <div className="loading-center"><div className="spinner" /></div>;
  if (!slot) return <div className="empty-state"><h3>Slot not found</h3></div>;

  const rows = {};
  seatSlots.forEach(ss=>{ const r=ss.seat?.rowLetter||'A'; if(!rows[r])rows[r]=[]; rows[r].push(ss); });

  const SEAT_TYPE_COLOR = { VIP:'#c97d1a', PREMIUM:'#2563a8', REGULAR:'#9c9285' };

  return (
    <div style={{ background:'var(--bg-secondary)', minHeight:'100vh' }}>
      <div className="container" style={{ maxWidth:'900px', paddingTop:'32px', paddingBottom:'48px' }}>
        <button onClick={()=>navigate(-1)} className="btn btn-ghost btn-sm" style={{ marginBottom:'20px', paddingLeft:0 }}>← Back</button>

        {/* Slot info bar */}
        <div className="card" style={{ padding:'18px 24px', marginBottom:'24px', display:'flex', gap:'24px', flexWrap:'wrap', alignItems:'center' }}>
          <div>
            <div style={{ fontFamily:'var(--font-display)', fontSize:'1.4rem', fontWeight:400 }}>{slot.event?.name}</div>
            <div style={{ fontSize:'13px', color:'var(--text-secondary)', marginTop:'4px', fontWeight:500 }}>
              📅 {slot.showDate} &nbsp;·&nbsp; ⏰ {slot.startTime?.slice(0,5)}–{slot.endTime?.slice(0,5)} &nbsp;·&nbsp; 📍 {slot.location?.locName}
            </div>
          </div>
          <div style={{ marginLeft:'auto', textAlign:'right' }}>
            <div style={{ fontSize:'12px', color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.6px', fontWeight:600 }}>Seats Left</div>
            <div style={{ fontFamily:'var(--font-display)', fontSize:'1.8rem', fontWeight:400, color:slot.seatsLeft>20?'var(--green)':'var(--gold)' }}>{slot.seatsLeft}</div>
          </div>
        </div>

        {step===3 ? <ConfirmationStep booking={booking} navigate={navigate} /> :
         step===2 ? <PaymentStep selectedSeats={selectedSeats} total={total} payMethod={payMethod} setPayMethod={setPayMethod} onBack={()=>setStep(1)} onConfirm={handleBook} processing={processing} /> : (
          <>
            {/* Legend */}
            <div style={{ display:'flex', gap:'20px', marginBottom:'20px', flexWrap:'wrap', alignItems:'center' }}>
              {[['Available','white','var(--border)'],['Selected','var(--accent)','var(--accent)'],].map(([label,bg,border])=>(
                <div key={label} style={{ display:'flex', alignItems:'center', gap:'8px', fontSize:'13px', color:'var(--text-secondary)', fontWeight:500 }}>
                  <div style={{ width:20, height:20, background:bg, border:`2px solid ${border}`, borderRadius:'4px', boxShadow:'var(--shadow-sm)' }} />{label}
                </div>
              ))}
              <div style={{ display:'flex', gap:'16px', marginLeft:'auto' }}>
                {Object.entries(SEAT_TYPE_COLOR).map(([type,color])=>(
                  <span key={type} style={{ fontSize:'12px', color, fontWeight:600, display:'flex', alignItems:'center', gap:'4px' }}>
                    <span style={{ width:8, height:8, background:color, borderRadius:'50%', display:'inline-block' }} />{type}
                  </span>
                ))}
              </div>
            </div>

            {/* Screen */}
            <div style={{ textAlign:'center', marginBottom:'24px', padding:'10px', background:'var(--bg-secondary)', borderRadius:'8px', border:'1.5px solid var(--border)', fontSize:'12px', color:'var(--text-muted)', letterSpacing:'8px', textTransform:'uppercase', fontWeight:600 }}>
              ── SCREEN ──
            </div>

            {/* Seats */}
            <div className="card" style={{ padding:'24px', overflowX:'auto' }}>
              {Object.entries(rows).sort().map(([row,seats])=>(
                <div key={row} style={{ display:'flex', alignItems:'center', gap:'6px', marginBottom:'8px' }}>
                  <span style={{ width:'20px', fontSize:'11px', color:'var(--text-muted)', fontFamily:'var(--font-mono)', textAlign:'center', flexShrink:0, fontWeight:600 }}>{row}</span>
                  <div style={{ display:'flex', gap:'5px', flexWrap:'wrap' }}>
                    {seats.sort((a,b)=>a.seat?.seatNo-b.seat?.seatNo).map(ss=>{
                      const isSelected = selectedSeats.find(s=>s.seatSlotId===ss.seatSlotId);
                      const c = SEAT_TYPE_COLOR[ss.seat?.seatType]||'#9c9285';
                      return (
                        <button key={ss.seatSlotId} onClick={()=>toggleSeat(ss)}
                          title={`${ss.seat?.rowLetter}${ss.seat?.seatNo} - ${ss.seat?.seatType} - ₹${ss.price}`}
                          style={{ width:'36px', height:'32px', borderRadius:'5px 5px 2px 2px', border:isSelected?`2px solid var(--accent)`:`2px solid ${c}55`, background:isSelected?'var(--accent)':`${c}18`, color:isSelected?'white':c, fontSize:'10px', fontWeight:700, cursor:'pointer', transition:'var(--transition)', fontFamily:'var(--font-mono)', boxShadow:isSelected?'var(--shadow-accent)':'var(--shadow-sm)' }}>
                          {ss.seat?.seatNo}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>

            {/* Sticky bar */}
            {selectedSeats.length>0 && (
              <div style={{ position:'sticky', bottom:0, background:'white', border:'1.5px solid var(--border)', borderRadius:'var(--radius)', padding:'16px 20px', display:'flex', justifyContent:'space-between', alignItems:'center', gap:'16px', flexWrap:'wrap', marginTop:'20px', boxShadow:'var(--shadow-lg)' }}>
                <div>
                  <div style={{ fontSize:'13px', color:'var(--text-secondary)', marginBottom:'3px', fontWeight:500 }}>
                    {selectedSeats.length} seat{selectedSeats.length>1?'s':''}: <strong>{selectedSeats.map(s=>`${s.seat?.rowLetter}${s.seat?.seatNo}`).join(', ')}</strong>
                  </div>
                  <div style={{ fontFamily:'var(--font-display)', fontSize:'1.5rem', fontWeight:400, color:'var(--accent)' }}>₹{total.toFixed(2)}</div>
                </div>
                <button onClick={()=>setStep(2)} className="btn btn-primary btn-lg">Proceed to Payment →</button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

const PaymentStep = ({ selectedSeats, total, payMethod, setPayMethod, onBack, onConfirm, processing }) => (
  <div style={{ maxWidth:'480px', margin:'0 auto' }}>
    <div className="card" style={{ padding:'28px', marginBottom:'16px' }}>
      <h3 style={{ fontFamily:'var(--font-display)', fontSize:'1.4rem', fontWeight:400, marginBottom:'20px', color:'var(--text-primary)' }}>Order Summary</h3>
      {selectedSeats.map(s=>(
        <div key={s.seatSlotId} style={{ display:'flex', justifyContent:'space-between', padding:'9px 0', borderBottom:'1px solid var(--border)', fontSize:'14px' }}>
          <span style={{ color:'var(--text-secondary)', fontWeight:500 }}>Seat {s.seat?.rowLetter}{s.seat?.seatNo} ({s.seat?.seatType})</span>
          <span style={{ fontWeight:700 }}>₹{parseFloat(s.price).toFixed(2)}</span>
        </div>
      ))}
      <div style={{ display:'flex', justifyContent:'space-between', marginTop:'14px' }}>
        <span style={{ fontWeight:600 }}>Total</span>
        <span style={{ fontFamily:'var(--font-display)', fontSize:'1.4rem', fontWeight:400, color:'var(--accent)' }}>₹{total.toFixed(2)}</span>
      </div>
    </div>
    <div className="card" style={{ padding:'28px' }}>
      <h3 style={{ fontFamily:'var(--font-display)', fontSize:'1.4rem', fontWeight:400, marginBottom:'20px' }}>Payment Method</h3>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'10px', marginBottom:'24px' }}>
        {PAYMENT_METHODS.map(m=>(
          <button key={m} onClick={()=>setPayMethod(m)} style={{ padding:'14px', borderRadius:'10px', border:'1.5px solid', borderColor:payMethod===m?'var(--accent)':'var(--border)', background:payMethod===m?'var(--accent-dim)':'var(--bg-card)', color:payMethod===m?'var(--accent)':'var(--text-secondary)', cursor:'pointer', fontWeight:700, fontSize:'13px', transition:'var(--transition)', fontFamily:'var(--font-body)', boxShadow:'var(--shadow-sm)' }}>
            {PM_ICONS[m]} {m}
          </button>
        ))}
      </div>
      <div style={{ display:'flex', gap:'12px' }}>
        <button onClick={onBack} className="btn btn-secondary" style={{ flex:1 }}>← Back</button>
        <button onClick={onConfirm} disabled={processing} className="btn btn-primary" style={{ flex:2 }}>
          {processing?'Processing...':'Pay ₹'+total.toFixed(2)}
        </button>
      </div>
    </div>
  </div>
);

const ConfirmationStep = ({ booking, navigate }) => (
  <div style={{ maxWidth:'480px', margin:'0 auto', textAlign:'center' }}>
    <div className="card" style={{ padding:'44px', border:'2px solid var(--green)', boxShadow:'0 8px 32px rgba(26,143,99,0.12)' }}>
      <div style={{ fontSize:'60px', marginBottom:'16px' }}>🎉</div>
      <h2 style={{ fontFamily:'var(--font-display)', fontSize:'2rem', fontWeight:400, color:'var(--green)', marginBottom:'6px' }}>Booking Confirmed!</h2>
      <p style={{ color:'var(--text-muted)', marginBottom:'28px', fontSize:'14px' }}>A confirmation email has been sent to you</p>
      <div style={{ background:'var(--bg-secondary)', borderRadius:'10px', padding:'18px', marginBottom:'24px', textAlign:'left' }}>
        <InfoRow label="Ref Code" value={booking?.reservation?.refCode} mono />
        <InfoRow label="Amount Paid" value={`₹${parseFloat(booking?.reservation?.amount||0).toFixed(2)}`} />
        <InfoRow label="Transaction ID" value={booking?.transaction?.transactionRef} mono />
        <InfoRow label="Status" value="✅ Confirmed" />
      </div>
      <div style={{ display:'flex', gap:'12px' }}>
        <button onClick={()=>navigate('/my-bookings')} className="btn btn-primary" style={{ flex:1 }}>View Bookings</button>
        <button onClick={()=>navigate('/')} className="btn btn-secondary" style={{ flex:1 }}>Browse More</button>
      </div>
    </div>
  </div>
);

const InfoRow = ({ label, value, mono }) => (
  <div style={{ display:'flex', justifyContent:'space-between', padding:'7px 0', borderBottom:'1px solid var(--border)', fontSize:'13px' }}>
    <span style={{ color:'var(--text-muted)', fontWeight:600 }}>{label}</span>
    <span style={{ fontFamily:mono?'var(--font-mono)':'var(--font-body)', fontWeight:700, color:'var(--text-primary)' }}>{value}</span>
  </div>
);

export default BookingPage;
